class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int[] count = new int[26];
        int unique = 0, maxFreq = 0;
        Map<String, Integer> freq = new HashMap<>();
        for (int i = 0; i < s.length(); i++) {
            count[s.charAt(i) - 'a']++;
            if (count[s.charAt(i) - 'a'] == 1) unique++;
            if (i >= minSize) {
                count[s.charAt(i - minSize) - 'a']--;
                if (count[s.charAt(i - minSize) - 'a'] == 0) unique--;
            }
            if (i >= minSize - 1 && unique <= maxLetters) {
                String substr = s.substring(i - minSize + 1, i + 1);
                freq.put(substr, freq.getOrDefault(substr, 0) + 1);
                maxFreq = Math.max(maxFreq, freq.get(substr));
            }
        }
        return maxFreq;
    }
}
